// 1. Récupération du CV et des deux nouvelles propriétés Notion
const properties = $('Webhook').item.json.body?.data?.properties || {};
const richTextArray = properties.CV?.rich_text || [];

// Extraction propre (sans double ?. )
const company = properties.Company?.rich_text?.[0]?.plain_text || 'company';
const jobTitle = properties.Job_Title?.rich_text?.[0]?.plain_text || 'job';

let mdText = richTextArray.map(block => block.plain_text || '').join('');

// 2. Parser Markdown avec nettoyage du "plain text" parasite
function robustMarkdownToHtml(md) {
  // Suppression des mentions "plain text" ou "plain_text" textuelles injectées par l'agent
  let cleanedMd = md.replace(/plain[\s_]text/gi, '');

  const lines = cleanedMd.split('\n');
  let htmlOutput = [];
  let inList = false;

  for (let line of lines) {
    let trimmed = line.trim();
    if (!trimmed.startsWith('-') && !trimmed.startsWith('*') && inList) {
      htmlOutput.push('</ul>');
      inList = false;
    }
    if (trimmed === '---' || trimmed === '***') {
      htmlOutput.push('<hr />');
      continue;
    }
    if (trimmed.startsWith('>')) {
      let content = line.replace(/^>\s*/, '').trim().replace(/^"(.*)"$/, '$1');
      htmlOutput.push(`<div class="summary-box">${content}</div>`);
      continue;
    }
    if (trimmed.startsWith('# ')) { htmlOutput.push(`<h1>${trimmed.substring(2)}</h1>`); continue; }
    if (trimmed.startsWith('## ')) { htmlOutput.push(`<h2>${trimmed.substring(3)}</h2>`); continue; }
    if (trimmed.startsWith('### ')) { htmlOutput.push(`<h3>${trimmed.substring(4)}</h3>`); continue; }

    if (trimmed.startsWith('-') || trimmed.startsWith('*')) {
      if (!inList) { htmlOutput.push('<ul>'); inList = true; }
      htmlOutput.push(`<li>${trimmed.replace(/^[\-\*]\s*/, '')}</li>`);
      continue;
    }
    if (trimmed !== '') htmlOutput.push(`<p>${line}</p>`);
  }
  if (inList) htmlOutput.push('</ul>');

  let finalBody = htmlOutput.join('\n');
  return finalBody.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
}

// Fonction utilitaire pour nettoyer les caractères spéciaux du futur nom de fichier
function slugify(text) {
  return text
    .toString()
    .toLowerCase()
    .normalize('NFD') // Supprime les accents
    .replace(/[\u0300-\u036f]/g, '')
    .trim()
    .replace(/\s+/g, '-') // Remplace les espaces par des tirets
    .replace(/[^a-z0-9\-]/g, ''); // Supprime le reste
}

const finalFileName = `javarre-${slugify(company)}-${slugify(jobTitle)}`;

return [
  {
    json: {
      compiledBody: robustMarkdownToHtml(mdText),
      pdfFileName: finalFileName
    }
  }
];

// 1. Récupération des données brutes du Webhook
const body = $('Webhook').item.json.body?.data || {};
const properties = body.properties || {};

const pageId = body.id;

// 2. Extraction de Company (Type: select)
let company = 'company';
if (properties.Company && properties.Company.select) {
  company = properties.Company.select.name || 'company';
}

// 3. Extraction de Job Title / Title (Type: title) - Tolère l'ancien et le nouveau nom
let jobTitle = 'job';
const targetProperty = properties.Title || properties["Job Title"];

if (targetProperty && targetProperty.title && targetProperty.title.length > 0) {
  jobTitle = targetProperty.title.plain_text || $input.first().json.body.data.properties["Job Title"].title[0].plain_text  || 'job';
}

// 4. Fonction locale slugify pour nettoyer les chaînes
function slugify(text) {
  return text
    .toString()
    .toLowerCase()
    .normalize('NFD') // Supprime les accents
    .replace(/[\u0300-\u036f]/g, '')
    .trim()
    .replace(/\s+/g, '-') // Remplace les espaces par des tirets
    .replace(/[^a-z0-9\-]/g, ''); // Élimine le reste
}

// 5. Forge du nom de fichier final personnalisé
const outputPdf = `javarre-${slugify(company)}_${slugify(jobTitle)}.pdf`;

// 6. Retour des variables propres
return [{ 
  json: { 
    pageId: pageId,
    company: company,
    jobTitle: jobTitle,
    outputPdf: outputPdf
  } 
}];

